use std::io::{stdin, stdout, Write, BufReader, BufRead, Read};

fn solve(input: &mut BufRead, output: &mut Write) {
    let mut input = BufReader::new(input);

    let mut line = String::with_capacity(100);
    input.read_line(&mut line).unwrap();
    let line = line.trim();

    if line.chars().next().unwrap() == '0' {
        output.write(b"0\n");
    } else if line.chars().filter(|&it| it == '1').count() == 1 {
        output.write(format!("{}\n", line.len() / 2).as_bytes());
    } else {
        output.write(format!("{}\n", (line.len() + 1) / 2).as_bytes());
    }

}

fn main() {
    let stdin = stdin();
    let stdout = stdout();
    solve(&mut stdin.lock(), &mut stdout.lock());
}
